 53→const AppContent: React.FC = () => {
 54→  const { t, tf, locale } = useTranslation();
 55→  const [currentView, setCurrentView] = useState<'home' | 'analyze' | 'results' | 'directory' | 'directory-entity' | 'login' | 'projects' | 'source-of-truth' | 'robots-txt' | 'history' | 'recharge' | 'account' | 'plan' | 'publisher-request' | 'schema-org' | 'smc-studio' | 'dashboard' | 'generative-tools' | 'clients' | 'affiliation' | 'messages' | 'alerts' | 'content-writer' | 'reputation' | 'bot-tracking'>('home');
 56→  const [viewHistory, setViewHistory] = useState<string[]>([]);
 57→  const [refreshKey, setRefreshKey] = useState(0); // Used to force remount of components
 58→  
 59→  const [analysisData, setAnalysisData] = useState<AnalysisResult | null>(null);
 60→  const [history, setHistory] = useState<AnalysisResult[]>([]);
 61→  
 62→  // Load history from DB on mount
