 67→
 68→  // Bibliothèques de contenu généré
 69→  const [smcLibrary, setSmcLibrary] = useState<SMCContent[]>([]); 
 70→  const [truthLibrary, setTruthLibrary] = useState<SMCContent[]>([]);
 71→  const [schemaLibrary, setSchemaLibrary] = useState<SMCContent[]>([]);
 72→  const [robotsLibrary, setRobotsLibrary] = useState<SMCContent[]>([]);
 73→
 74→  const [isAnalyzing, setIsAnalyzing] = useState(false);
