 89→  // Calcul du nombre de projets consommé sur le mois en cours (Renouvellement mensuel)
 90→  const monthlyProjectCount = useMemo(() => {
 91→    if (history.length === 0) return 0;
 92→
 93→    // Définir le début du cycle de facturation (simulé au 1er du mois courant)
 94→    const now = new Date();
 95→    const billingCycleStart = new Date(now.getFullYear(), now.getMonth(), 1);
 96→
 97→    // 1. Identifier la date de création (première analyse) de chaque domaine
 98→    const projectCreationDates = new Map<string, Date>();
 99→    
100→    history.forEach(h => {
101→        let hostname;
102→        try { hostname = new URL(h.url).hostname; } catch(e) { hostname = h.url; }
103→        
104→        const analysisDate = new Date(h.timestamp);
105→        
106→        if (!projectCreationDates.has(hostname)) {
107→            projectCreationDates.set(hostname, analysisDate);
108→        } else {
109→            // On garde la date la plus ancienne trouvée pour ce domaine
110→            if (analysisDate < projectCreationDates.get(hostname)!) {
111→                projectCreationDates.set(hostname, analysisDate);
112→            }
113→        }
114→    });
115→
116→    // 2. Compter uniquement les projets dont la "création" est postérieure au début du cycle
117→    let count = 0;
118→    projectCreationDates.forEach((creationDate) => {
119→        if (creationDate >= billingCycleStart) {
120→            count++;
121→        }
122→    });
123→    
124→    return count;
125→  }, [history]);
