277→  const handleSaveSolution = useCallback((analysisId: string, recommendationId: string, solution: GeneratedSolution) => {
278→    const timestamp = new Date().toISOString();
279→    const solutionWithMeta = { ...solution, timestamp };
280→
281→    setAnalysisData(prev => {
282→        if (!prev || prev.timestamp !== analysisId) return prev;
283→        
