289→            }
290→        };
291→    });
292→
293→    // We need to find the index in the history to update the DB
294→    setHistory(prevHistory => {
295→        const index = prevHistory.findIndex(item => item.timestamp === analysisId);
296→        if (index !== -1) {
297→            const updatedItem = {
298→                ...prevHistory[index],
299→                generatedSolutions: {
300→                    ...(prevHistory[index].generatedSolutions || {}),
301→                    [recommendationId]: solutionWithMeta
302→                }
303→            };
304→            // Persist using db service
305→            const newHistory = [...prevHistory];
306→            newHistory[index] = updatedItem;
307→            // Note: calling db.update relies on index which matches prevHistory order if initialized from DB
308→            db.update(index, updatedItem);
309→            return newHistory;
310→        }
311→        return prevHistory;
312→    });
313→  }, []); 
